const grpc = require('grpc');
const protoLoader = require('@grpc/proto-loader');

const packageDefinition = protoLoader.loadSync(
  'service.proto', // Replace with your .proto file path
  {
    keepCase: true,
    longs: String,
    enums: String,
    defaults: true,
    oneofs: true
  }
);

const serviceProto = grpc.loadPackageDefinition(packageDefinition).service; // Replace 'service' with your package name

function createMetadata(headers) {
  const metadata = new grpc.Metadata();
  Object.keys(headers).forEach(key => {
    if (key.startsWith('grpc-')) return; // Skip gRPC specific headers
    metadata.add(key, headers[key]);
  });
  return metadata;
}

const client = new serviceProto.Service('localhost:50051', grpc.credentials.createInsecure()); // Replace 'localhost:50051' and 'Service' with your server address and service name

function callGrpcMethod(methodName, request, headers, callback) {
  const metadata = createMetadata(headers);
  client[methodName](request, metadata, (error, response) => {
    if (error) {
      console.error('gRPC call failed:', error);
      return callback(error, null);
    }
    callback(null, response);
  });
}

